	(188, '_site_transient_feed_6f409681938158427d2ded6eb1b9ea27', 'a:6:{s:5:"child";a:1:{s:0:"";a:1:{s:3:"rss";a:1:{i:0;a:6:{s:4:"data";s:5:"\n\n	\n	";s:7:"attribs";a:1:{s:0:"";a:1:{s:7:"version";s:3:"2.0";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:1:{s:0:"";a:1:{s:7:"channel";a:1:{i:0;a:6:{s:4:"data";s:141:"\n\n		\n		\n		\n				\n		\n		\n\n		\n		\n					\n				\n\n			\n				\n\n			\n				\n\n			\n				\n\n			\n				\n\n			\n				\n\n			\n				\n\n			\n				\n\n			\n				\n\n			\n				\n\n					\n		\n	";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:7:{s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:55:"WordPress | サポートフォーラム » 返信一覧";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:44:"https://ja.wordpress.org/support/forums/feed";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:0:"";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:13:"lastBuildDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Sat, 27 Jun 2026 15:43:06 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:9:"generator";a:1:{i:0;a:5:{s:4:"data";s:36:"https://bbpress.org/?v=2.7.0-alpha-2";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:8:"language";a:1:{i:0;a:5:{s:4:"data";s:2:"ja";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"item";a:10:{i:0;a:6:{s:4:"data";s:55:"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:252:"https://ja.wordpress.org/support/topic/%e7%ae%a1%e7%90%86%e7%94%bb%e9%9d%a2%e3%81%ae%e3%83%a1%e3%83%8b%e3%83%a5%e3%83%bc%e3%81%8c%e5%9b%ba%e5%ae%9a%e3%83%9a%e3%83%bc%e3%82%b8%e3%81%a0%e3%81%91%e8%8b%b1%e8%aa%9e%e4%ba%a4%e3%81%98%e3%82%8a/#post-11694239";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:86:"返信先: 管理画面のメニューが固定ページだけ英語交じりになる";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:252:"https://ja.wordpress.org/support/topic/%e7%ae%a1%e7%90%86%e7%94%bb%e9%9d%a2%e3%81%ae%e3%83%a1%e3%83%8b%e3%83%a5%e3%83%bc%e3%81%8c%e5%9b%ba%e5%ae%9a%e3%83%9a%e3%83%bc%e3%82%b8%e3%81%a0%e3%81%91%e8%8b%b1%e8%aa%9e%e4%ba%a4%e3%81%98%e3%82%8a/#post-11694239";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 24 Jun 2026 04:17:31 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:1773:"\n						\n						<p class="wp-block-paragraph">ご返信ありがとうございます。</p>\n\n\n\n<p class="wp-block-paragraph">WordPressは最近7.0になりました。<br />テーマは自作です。また、テーマをTwenty Twenty-Fiveに変更してもメニューは変わりはありませんでした。<br />wp-contentにmu-pluginsというフォルダはありません。<br />本体ファイルの再インストールは何度か試しましたが、特に変化はないように思いました。</p>\n\n\n\n<p class="wp-block-paragraph">function.phpの内容も見たのですが特にメニューに何か設定していることもなさそうです。</p>\n\n\n\n<blockquote class="wp-block-quote is-layout-flow wp-block-quote-is-layout-flow">\n<p class="wp-block-paragraph">または 古い本体ファイル・翻訳ファイルの不整合あたりを疑って確認するのがよさそうです。</p>\n</blockquote>\n\n\n\n<p class="wp-block-paragraph">ありがとうございます。<br />サイトの言語設定をUSにしてから日本語に戻したり、ユーザー設定の言語をサイトデフォルトからUSにしたり日本語にしたりしたのですが、今のところ改善は見られません…</p>\n\n\n\n<p class="wp-block-paragraph">一番最初にインストールしたのがおそらく8年以上前で、去年の末までPHP7.3で動いていたものなので、もろもろ不具合があるのかもしれませんね。<br />特にものすごく困っているわけではないのですが、直せるものなら直したいと思いますので、何か思いつくことなどございましたらアドバイス頂戴できれば幸いです。<br />引き続きよろしくお願いいたします。</p>\n						\n					";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:18:"ごはんですよ";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:1;a:6:{s:4:"data";s:55:"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:198:"https://ja.wordpress.org/support/topic/%e5%95%86%e5%93%81%e3%83%9e%e3%83%bc%e3%82%af%e3%81%8c%e3%81%8d%e3%81%a1%e3%82%93%e3%81%a8%e8%a1%a8%e7%a4%ba%e3%81%95%e3%82%8c%e3%81%aa%e3%81%84/#post-11694238";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:59:"返信先: 商品マークがきちんと表示されない";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:198:"https://ja.wordpress.org/support/topic/%e5%95%86%e5%93%81%e3%83%9e%e3%83%bc%e3%82%af%e3%81%8c%e3%81%8d%e3%81%a1%e3%82%93%e3%81%a8%e8%a1%a8%e7%a4%ba%e3%81%95%e3%82%8c%e3%81%aa%e3%81%84/#post-11694238";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Wed, 24 Jun 2026 04:12:41 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:389:"\n						\n						<blockquote class="wp-block-quote is-layout-flow wp-block-quote-is-layout-flow">\n<p class="wp-block-paragraph">※ 最後の行の 4px を 2px にするなどして高さを調整してみてください。</p>\n</blockquote>\n\n\n\n<p class="wp-block-paragraph">今回の場合はマージンではなく👆これですねー。調整してみてください。</p>\n						\n					";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";