ちんと表示されない";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:198:"https://ja.wordpress.org/support/topic/%e5%95%86%e5%93%81%e3%83%9e%e3%83%bc%e3%82%af%e3%81%8c%e3%81%8d%e3%81%a1%e3%82%93%e3%81%a8%e8%a1%a8%e7%a4%ba%e3%81%95%e3%82%8c%e3%81%aa%e3%81%84/#post-11694230";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 22 Jun 2026 15:22:30 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:3867:"\n						\n						<p class="wp-block-paragraph">▼こちらの場合は</p>\n\n\n\n<figure class="wp-block-embed is-type-rich is-provider-imgur wp-block-embed-imgur"><div class="wp-block-embed__wrapper">\n<blockquote class="imgur-embed-pub" lang="en" data-id="E64rpnP"><a href="https://imgur.com/E64rpnP" rel="nofollow ugc">View post on imgur.com</a></blockquote><script async src="//s.imgur.com/min/embed.js" charset="utf-8"></script>\n</div></figure>\n\n\n\n<p class="wp-block-paragraph">以下の CSS でラベル色を制御</p>\n\n\n\n<pre class="wp-block-code"><code>/* 接触冷感素材 */<br />.fs-c-productMark__mark--38 {<br />    color: #fff;<br />    background: #39bddb;<br />}</code></pre>\n\n\n\n<p class="wp-block-paragraph">―</p>\n\n\n\n<p class="wp-block-paragraph">▼こちらの場合は</p>\n\n\n\n<figure class="wp-block-embed is-type-rich is-provider-imgur wp-block-embed-imgur"><div class="wp-block-embed__wrapper">\n<blockquote class="imgur-embed-pub" lang="en" data-id="JiWfHPt"><a href="https://imgur.com/JiWfHPt" rel="nofollow ugc">View post on imgur.com</a></blockquote><script async src="//s.imgur.com/min/embed.js" charset="utf-8"></script>\n</div></figure>\n\n\n\n<p class="wp-block-paragraph">以下の CSS でラベル色を制御</p>\n\n\n\n<pre class="wp-block-code"><code>/* 2点20％OFF */<br />.fs-c-productMark__mark--17 {<br />    color: #5c5c5c;<br />    background: #d9bae3;<br />}</code></pre>\n\n\n\n<p class="wp-block-paragraph">―</p>\n\n\n\n<p class="wp-block-paragraph">▼こちらの場合は</p>\n\n\n\n<figure class="wp-block-embed is-type-rich is-provider-imgur wp-block-embed-imgur"><div class="wp-block-embed__wrapper">\n<blockquote class="imgur-embed-pub" lang="en" data-id="0J507lf"><a href="https://imgur.com/0J507lf" rel="nofollow ugc">View post on imgur.com</a></blockquote><script async src="//s.imgur.com/min/embed.js" charset="utf-8"></script>\n</div></figure>\n\n\n\n<p class="wp-block-paragraph">以下の CSS でラベル色を制御</p>\n\n\n\n<pre class="wp-block-code"><code>/* 速乾×UVカット */<br />.fs-c-productMark__mark--37 {<br />    color: #fff;<br />    background: #289ca1;<br />}</code></pre>\n\n\n\n<p class="wp-block-paragraph">―</p>\n\n\n\n<p class="wp-block-paragraph">･･･というふうに、ラベルごとに色分けがなされているようですよ。</p>\n\n\n\n<p class="wp-block-paragraph">前回のものと合わせると▼こんなふうになると思います。<br />(他のラベルの色も拾ってきてみています。)</p>\n\n\n\n<pre class="wp-block-code"><code>/* 動画あり */<br />.fs-c-productMark__mark--7 {<br />    color: #5c5c5c;<br />    background: #ffb3b3;<br />}<br />/* 2点20％OFF */<br />.fs-c-productMark__mark--17 {<br />    color: #5c5c5c;<br />    background: #d9bae3;<br />}<br />/* 速乾×UVカット */<br />.fs-c-productMark__mark--37 {<br />    color: #fff;<br />    background: #289ca1;<br />}<br />/* 接触冷感素材 */<br />.fs-c-productMark__mark--38 {<br />    color: #fff;<br />    background: #39bddb;<br />}<br />/* 30%OFF・50%OFF */<br />.fs-c-productMark__mark--42 {<br />    color: #fff;<br />    background: #f35aa3;<br />}<br />/* 共通 */<br />.fs-c-productMark__mark {<br />    font-size: 0.8em;<br />    padding: 4px 8px;<br />}</code></pre>\n\n\n\n<p class="wp-block-paragraph">※ 最後の行の 4px を 2px にするなどして高さを調整してみてください。</p>\n\n\n<ul id="bbp-reply-revision-log-11694230" class="bbp-reply-revision-log">\n\n	<li id="bbp-reply-revision-log-11694230-item-11694231" class="bbp-reply-revision-log-item">\n		この返信は5日前に<a href="https://ja.wordpress.org/support/users/setouchikotori/" title="瀬戸内ことり (Setouchi Kotori) のプロフィールを表示" class="bbp-author-link"><span  class="bbp-author-name">瀬戸内ことり (Setouchi Kotori)</span></a>が編集しました。\n	</li>\n\n</ul>\n\n						\n					";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:36:"瀬戸内ことり (Setouchi Kotori)";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}i:9;a:6:{s:4:"data";s:55:"\n					\n					\n					\n					\n					\n\n					\n\n					\n					\n				";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";s:5:"child";a:2:{s:0:"";a:5:{s:4:"guid";a:1:{i:0;a:5:{s:4:"data";s:252:"https://ja.wordpress.org/support/topic/%e8%87%aa%e3%82%b5%e3%82%a4%e3%83%88%e3%81%ae%e8%a1%a8%e7%a4%ba%e3%81%8c%e7%9c%9f%e3%81%a3%e7%99%bd%e3%81%ab%e3%81%aa%e3%82%8a%e3%83%ad%e3%82%b0%e3%82%a4%e3%83%b3%e3%82%82%e8%a1%a8%e7%a4%ba%e3%81%95/#post-11694228";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:5:"title";a:1:{i:0;a:5:{s:4:"data";s:86:"返信先: 自サイトの表示が真っ白になりログインも表示されない";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:252:"https://ja.wordpress.org/support/topic/%e8%87%aa%e3%82%b5%e3%82%a4%e3%83%88%e3%81%ae%e8%a1%a8%e7%a4%ba%e3%81%8c%e7%9c%9f%e3%81%a3%e7%99%bd%e3%81%ab%e3%81%aa%e3%82%8a%e3%83%ad%e3%82%b0%e3%82%a4%e3%83%b3%e3%82%82%e8%a1%a8%e7%a4%ba%e3%81%95/#post-11694228";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:7:"pubDate";a:1:{i:0;a:5:{s:4:"data";s:31:"Mon, 22 Jun 2026 07:54:00 +0000";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}s:11:"description";a:1:{i:0;a:5:{s:4:"data";s:559:"\n						\n						<p class="wp-block-paragraph">返信ありがとうございます</p>\n\n\n\n<p class="wp-block-paragraph">本日、ロリポップサーバーに電話確認し</p>\n\n\n\n<p class="wp-block-paragraph">バックアップをとっていたデータを戻し</p>\n\n\n\n<p class="wp-block-paragraph">復旧しました。</p>\n\n\n\n<p class="wp-block-paragraph">現在、問題はなくなりましたので</p>\n\n\n\n<p class="wp-block-paragraph">質問を終わります</p>\n\n\n\n<p class="wp-block-paragraph">ありがとうございました。</p>\n						\n					";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}s:32:"http://purl.org/dc/elements/1.1/";a:1:{s:7:"creator";a:1:{i:0;a:5:{s:4:"data";s:9:"apuriblog";s:7:"attribs";a:0:{}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}s:27:"http://www.w3.org/2005/Atom";a:1:{s:4:"link";a:1:{i:0;a:5:{s:4:"data";s:0:"";s:7:"attribs";a:1:{s:0:"";a:3:{s:4:"href";s:44:"https://ja.wordpress.org/support/forums/feed";s:3:"rel";s:4:"self";s:4:"type";s:19:"application/rss+xml";}}s:8:"xml_base";s:0:"";s:17:"xml_base_explicit";b:0;s:8:"xml_lang";s:0:"";}}}}}}}}}}}}s:4:"type";i:128;s:7:"headers";a:10:{s:6:"server";s:5:"nginx";s:4:"date";s:29:"Sat, 27 Jun 2026 15:53:50 GMT";s:12:"content-type";s:34:"application/rss+xml; charset=UTF-8";s:4:"vary";s:37:"Accept-Encoding, accept, content-type";s:6:"x-olaf";s:3:"⛄";s:12:"x-robots-tag";s:15:"noindex, follow";s:15:"x-frame-options";s:10:"SAMEORIGIN";s:16:"content-encoding";s:4:"gzip";s:7:"alt-svc";s:5:"clear";s:4:"x-nc";s:9:"HIT ord 1";}s:5:"build";i:1782573748;s:21:"cache_expiration_time";i:1782618829;s:23:"__cache_expiration_time";i:1782618829;}', 'off');
